SELECT SITE_CD AS siteCd , POP_GRP_ID AS popGrpId , LANG_SE AS langSe , POP_GRP_NM AS popGrpNm , USE_YN AS useYn , POP_GRP_ORD AS popGrpOrd , TO_CHAR(CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS crtAt , TO_CHAR(UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS updAt FROM CMS_POP_GRP WHERE SITE_CD = #{siteCd}
AND LANG_SE = #{langSe}
ORDER BY POP_GRP_ORD ASC, POP_GRP_ID ASC

SELECT SITE_CD AS siteCd , POP_GRP_ID AS popGrpId , LANG_SE AS langSe , POP_GRP_NM AS popGrpNm , USE_YN AS useYn , POP_GRP_ORD AS popGrpOrd , TO_CHAR(CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS crtAt , TO_CHAR(UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS updAt FROM CMS_POP_GRP WHERE SITE_CD = #{siteCd} AND POP_GRP_ID = #{popGrpId}
AND LANG_SE = #{langSe}
FETCH FIRST 1 ROWS ONLY

