mapper.update:
UPDATE CMS_POP_GRP
   SET POP_GRP_NM  = #{vo.popGrpNm}
     , USE_YN      = NVL(#{vo.useYn}, USE_YN)
     , POP_GRP_ORD = #{vo.popGrpOrd}
     , 
 WHERE SITE_CD     = #{siteCd}
   AND POP_GRP_ID  = #{popGrpId}
   AND LANG_SE     = #{vo.langSe}

